### ✅ 二叉排序树的 Java 实现

```java
// 定义节点类
class TreeNode {
    int value;
    TreeNode left;
    TreeNode right;

    public TreeNode(int value) {
        this.value = value;
        this.left = null;
        this.right = null;
    }
}

// 二叉排序树类
public class BinarySearchTree {

    private TreeNode root;

    // 构造函数
    public BinarySearchTree() {
        this.root = null;
    }

    // 插入节点
    public void insert(int value) {
        root = insertRecursive(root, value);
    }

    private TreeNode insertRecursive(TreeNode current, int value) {
        if (current == null) {
            return new TreeNode(value);
        }

        if (value < current.value) {
            current.left = insertRecursive(current.left, value);
        } else if (value > current.value) {
            current.right = insertRecursive(current.right, value);
        }

        return current;
    }

    // 查找节点
    public boolean contains(int value) {
        return containsRecursive(root, value);
    }

    private boolean containsRecursive(TreeNode current, int value) {
        if (current == null) {
            return false;
        }

        if (value == current.value) {
            return true;
        } else if (value < current.value) {
            return containsRecursive(current.left, value);
        } else {
            return containsRecursive(current.right, value);
        }
    }

    // 删除节点
    public void delete(int value) {
        root = deleteRecursive(root, value);
    }

    private TreeNode deleteRecursive(TreeNode current, int value) {
        if (current == null) {
            return null;
        }

        if (value == current.value) {
            // 找到要删除的节点，处理三种情况：无子节点、一个子节点、两个子节点
            if (current.left == null && current.right == null) {
                return null;
            } else if (current.right == null) {
                return current.left;
            } else if (current.left == null) {
                return current.right;
            } else {
                // 有两个子节点，找到右子树的最小值节点（中序后继）
                int smallestValue = findSmallestValue(current.right);
                current.value = smallestValue;
                current.right = deleteRecursive(current.right, smallestValue);
                return current;
            }
        } else if (value < current.value) {
            current.left = deleteRecursive(current.left, value);
            return current;
        } else {
            current.right = deleteRecursive(current.right, value);
            return current;
        }
    }

    private int findSmallestValue(TreeNode current) {
        return current.left == null ? current.value : findSmallestValue(current.left);
    }

    // 中序遍历（按升序输出）
    public void inOrderTraversal() {
        inOrderTraversalRecursive(root);
    }

    private void inOrderTraversalRecursive(TreeNode node) {
        if (node != null) {
            inOrderTraversalRecursive(node.left);
            System.out.print(node.value + " ");
            inOrderTraversalRecursive(node.right);
        }
    }

    // 测试主方法
    public static void main(String[] args) {
        BinarySearchTree bst = new BinarySearchTree();

        // 插入节点
        bst.insert(50);
        bst.insert(30);
        bst.insert(70);
        bst.insert(20);
        bst.insert(40);
        bst.insert(60);
        bst.insert(80);

        System.out.println("中序遍历结果（升序）:");
        bst.inOrderTraversal(); // 输出: 20 30 40 50 60 70 80

        // 查找节点
        System.out.println("\n\n查找 40: " + bst.contains(40)); // true
        System.out.println("查找 90: " + bst.contains(90)); // false

        // 删除节点
        System.out.println("\n删除 50 前的中序遍历:");
        bst.inOrderTraversal();

        bst.delete(50);

        System.out.println("\n删除 50 后的中序遍历:");
        bst.inOrderTraversal(); // 应为 20 30 40 60 70 80 （50 被删除）
    }
}
```

